    public class RadioListOutlineStyleTests
    {
        [Fact]
        public void RadioList_ShouldHaveIsOutlineParameter()
        {
            // Arrange & Act
            var radioList = new RadioList<string>();

            // Assert
            // This test will fail initially - we need to add the IsOutline parameter
        }

