        public void RadioList_ButtonStyle_ShouldApplyOutlineClasses_WhenIsOutlineTrue()
        {
            // Arrange
            var radioList = new RadioList<string>()
            {
                IsButton = true,
                IsOutline = true,
                Color = Color.Primary
