            Assert.DoesNotContain("btn-outline-primary", buttonClass);
        }

        // Helper method to access private ButtonClassString property
        private string GetPrivateButtonClassString(RadioList<string> radioList)
        {
            // This is just a placeholder - actual implementation would use reflection
            // to access the private ButtonClassString property
            return "";
        }
    }
}

